def verify(workspace_path, external_services_path=None):
    # Find the escalation log file
    wb_files = list(Path(workspace_path).glob("*Escalation_Log*.xlsx")) + list(Path(workspace_path).glob("*escalation_log*.xlsx"))
    if not wb_files:
        all_xlsx = list(Path(workspace_path).glob("*.xlsx"))
        wb_files = [f for f in all_xlsx if "escalation" in f.name.lower() and "log" in f.name.lower()]
    if not wb_files:
        return {"pass": False, "score": 0.0, "feedback": "PBC_Escalation_Log.xlsx not found in workspace"}

    wb_path = wb_files[0]
    try:
        wb = openpyxl.load_workbook(wb_path, data_only=True)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to open workbook: {e}"}

    ws = wb.active

    # Determine column indices for Category and Resolution_Tkg from header row
    header_row = 1
    max_col = ws.max_column or 20
    cat_col = None
    res_col = None
    for col_idx in range(1, max_col + 1):
        val = ws.cell(row=header_row, column=col_idx).value
        if val is not None:
            val_str = str(val).strip().lower()
            if val_str in ("category",):
                cat_col = col_idx
            if "resolution" in val_str or "tkg" in val_str:
                res_col = col_idx

    # Fallback: if headers not detected, assume common column positions
    # Try row 2 as header as well if row 1 didn't work
    if cat_col is None or res_col is None:
        for try_header in [2]:
            for col_idx in range(1, max_col + 1):
                val = ws.cell(row=try_header, column=col_idx).value
                if val is not None:
                    val_str = str(val).strip().lower()
                    if val_str in ("category",) and cat_col is None:
                        cat_col = col_idx
                    if ("resolution" in val_str or "tkg" in val_str) and res_col is None:
                        res_col = col_idx

    # If still not found, use defaults (common layout: Category might be col D or E, Resolution_Tkg might be col E or later)
    # We'll do a broader search across all columns for the expected values
    if cat_col is None or res_col is None:
        # Scan all columns to find which ones contain 'Financial' and which contain 'Escalated to RCM Manager'
        for col_idx in range(1, max_col + 1):
            for row_idx in range(3, 9):
                val = ws.cell(row=row_idx, column=col_idx).value
                if val is not None:
                    val_str = str(val).strip()
                    if val_str.lower() == "financial" and cat_col is None:
                        cat_col = col_idx
                    if "escalated to rcm manager" in val_str.lower() and res_col is None:
                        res_col = col_idx

    failures = []

    expected_category = "Financial"
    expected_resolution = "Escalated to RCM Manager - 2026-04-09"

    rows_to_check = [3, 4, 5, 6, 7, 8]

    # Check Category column
    if cat_col is not None:
        for row in rows_to_check:
            val = ws.cell(row=row, column=cat_col).value
            val_str = str(val).strip() if val is not None else ""
            if val_str.lower() != expected_category.lower():
                failures.append(f"Row {row} Category (col {cat_col})='{val_str}', expected '{expected_category}'")
    else:
        failures.append("Could not identify Category column in the spreadsheet")

    # Check Resolution_Tkg column
    if res_col is not None:
        for row in rows_to_check:
            val = ws.cell(row=row, column=res_col).value
            val_str = str(val).strip() if val is not None else ""
            if val_str != expected_resolution:
                # Be a bit lenient: check case-insensitive and allow minor formatting differences
                if val_str.lower().replace(" ", "") != expected_resolution.lower().replace(" ", ""):
                    failures.append(f"Row {row} Resolution_Tkg (col {res_col})='{val_str}', expected '{expected_resolution}'")
    else:
        failures.append("Could not identify Resolution_Tkg column in the spreadsheet")

    if failures:
        return {"pass": False, "score": 0.0, "feedback": f"Failures found: {'; '.join(failures)}"}

    return {"pass": True, "score": 1.0, "feedback": f"All rows 3-8 contain Category='{expected_category}' and Resolution_Tkg='{expected_resolution}'"}

