        else:
            return {"pass": False, "score": 0.0, "feedback": f"PBC_Escalation_Log.xlsx should have exactly 7 data rows (excluding headers), but found {data_row_count} data rows."}
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error reading 'PBC_Escalation_Log.xlsx': {str(e)}"}
